+import Foundation
+import WhisperKit
+
+struct WhisperInitializationRequest: Equatable, Sendable {
+    var variant: String
+    var modelFolderURL: URL
+    var verbose: Bool
+    var logLevel: WhisperLogLevel
+    var prewarm: Bool
+    var load: Bool
+}
+
+protocol WhisperRuntimeLoading: AnyObject, Sendable {
+    func download(
+        variant: String,
+        downloadBase: URL,
+        progress: @escaping @Sendable (Double) -> Void
+    ) async throws -> URL
+
+    func initialize(_ request: WhisperInitializationRequest) async throws
+}
+
+@MainActor
+final class WhisperSpeechModelLoader: SpeechModelLoading {
+    private let runtime: any WhisperRuntimeLoading
+    private let fileManager: FileManager
+    private let whisperModelsRootURL: URL
+
+    init(
+        runtime: any WhisperRuntimeLoading = WhisperRuntimeBridge(),
+        fileManager: FileManager = .default,
+        whisperModelsRootURL: URL? = nil
+    ) {
+        self.runtime = runtime
+        self.fileManager = fileManager
+        self.whisperModelsRootURL = whisperModelsRootURL ?? AppSupportPaths.whisperModelsRootURL(fileManager: fileManager)
+    }
+
+    func isCached(_ model: SpeechModelDescriptor) async throws -> Bool {
+        fileManager.fileExists(atPath: canonicalModelURL(for: model).path)
+    }
+
+    func download(_ model: SpeechModelDescriptor, progress: @Sendable @escaping (Double) -> Void) async throws {
+        let variant = try whisperVariant(for: model)
+        try ensureDirectoryExists(at: whisperModelsRootURL)
+
+        let downloadedURL = try await runtime.download(
+            variant: variant,
+            downloadBase: whisperModelsRootURL,
+            progress: progress
+        )
+
+        _ = try activateDownloadedModel(at: downloadedURL, for: model)
+    }
+
+    func load(_ model: SpeechModelDescriptor, whisperOptions: WhisperRuntimeOptions) async throws {
+        let modelFolderURL = canonicalModelURL(for: model)
+        guard fileManager.fileExists(atPath: modelFolderURL.path) else {
+            throw WhisperSpeechModelLoaderError.modelFilesMissing(modelFolderURL.path)
+        }
+
+        try await runtime.initialize(
+            WhisperInitializationRequest(
+                variant: try whisperVariant(for: model),
+                modelFolderURL: modelFolderURL,
+                verbose: whisperOptions.verbose,
+                logLevel: whisperOptions.logLevel,
+                prewarm: whisperOptions.prewarm,
+                load: whisperOptions.load
+            )
+        )
+    }
+
+    private func activateDownloadedModel(at downloadedURL: URL, for model: SpeechModelDescriptor) throws -> URL {
+        let canonicalURL = canonicalModelURL(for: model)
+        try ensureDirectoryExists(at: canonicalURL.deletingLastPathComponent())
+
+        if canonicalURL.standardizedFileURL == downloadedURL.standardizedFileURL {
+            return canonicalURL
+        }
+
+        if fileManager.fileExists(atPath: canonicalURL.path) {
+            return canonicalURL
+        }
+
+        guard fileManager.fileExists(atPath: downloadedURL.path) else {
+            throw WhisperSpeechModelLoaderError.modelFilesMissing(downloadedURL.path)
+        }
+
+        try fileManager.moveItem(at: downloadedURL, to: canonicalURL)
+        return canonicalURL
+    }
+
+    private func canonicalModelURL(for model: SpeechModelDescriptor) -> URL {
+        model.cachePathComponents.reduce(whisperModelsRootURL) { url, component in
+            url.appending(path: component, directoryHint: .isDirectory)
+        }
+    }
+
+    private func whisperVariant(for model: SpeechModelDescriptor) throws -> String {
+        guard model.backend == .whisper else {
+            throw WhisperSpeechModelLoaderError.unsupportedModel(model.id)
+        }
+
+        guard let variant = model.whisperVariant else {
+            throw WhisperSpeechModelLoaderError.unsupportedModel(model.id)
+        }
+
+        return variant
+    }
+
+    private func ensureDirectoryExists(at url: URL) throws {
+        try fileManager.createDirectory(at: url, withIntermediateDirectories: true)
+    }
+}
+
+private final class WhisperRuntimeBridge: WhisperRuntimeLoading, @unchecked Sendable {
+    private var whisperKit: WhisperKit?
+
+    func download(
+        variant: String,
+        downloadBase: URL,
+        progress: @escaping @Sendable (Double) -> Void
+    ) async throws -> URL {
+        try await WhisperKit.download(
+            variant: variant,
+            downloadBase: downloadBase,
+            useBackgroundSession: false
+        ) { downloadProgress in
+            progress(downloadProgress.fractionCompleted)
+        }
+    }
+
+    func initialize(_ request: WhisperInitializationRequest) async throws {
+        let config = WhisperKitConfig(
+            model: request.variant,
+            modelFolder: request.modelFolderURL.path,
+            verbose: request.verbose,
+            logLevel: runtimeLogLevel(for: request.logLevel),
+            prewarm: request.prewarm,
+            load: request.load,
+            download: false
+        )
+        whisperKit = try await WhisperKit(config)
+    }
+
+    private func runtimeLogLevel(for logLevel: WhisperLogLevel) -> Logging.LogLevel {
+        switch logLevel {
+        case .errorOnly:
+            return .error
+        }
+    }
+}
+
+private enum WhisperSpeechModelLoaderError: LocalizedError {
+    case unsupportedModel(String)
+    case modelFilesMissing(String)
+
+    var errorDescription: String? {
+        switch self {
+        case let .unsupportedModel(modelID):
+            return "Unsupported speech model: \(modelID)"
+        case let .modelFilesMissing(path):
+            return "Speech model files are missing at \(path)."
+        }
+    }
+}
